15	const BASE_PRICES: Record<string, number> = {
16	  sword: 100,
17	  amulet: 60,
18	  staff: 80,
19	  potion: 40,
20	  rune: 25,
21	  moonstone: 25,
22	};
23	
24	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
25	const BLOCK_PRICE: Record<string, number> = {
26	  rune: 60,
27	  moonstone: 60,
28	};
29	
30	export interface QuoteContext {
31	  previousQuoteCount?: number;
32	}
33	
34	export function quote(customer: Customer, items: Item[], context?: QuoteContext): number {
35	  let total = 0;
36	  let policyBase = 0;
37	  const componentCounts: Record<string, number> = {};
38	  for (const item of items) {
39	    if (!(item.type in BASE_PRICES)) {
40	      throw new Error(`Unknown item type: ${item.type}`);
41	    }
42	    if (COMPONENT_TYPES.has(item.type)) {
43	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
44	      continue;
45	    }
46	    const base = BASE_PRICES[item.type] ?? 0;
47	    const curse = item.cursed ? base * 0.5 : 0;
48	    const highEnchant = (item.enchantment ?? 0) >= 5 ? base * 0.3 : 0;
49	    total += base + curse + highEnchant + base * FIRST_INSURANCE_SURCHARGE_RATE;
50	    policyBase += base;
51	  }
52	  for (const type of Object.keys(componentCounts)) {
53	    const count = componentCounts[type];
54	    const unitPrice = BASE_PRICES[type] ?? 0;
55	    const base = count === 3 ? BLOCK_PRICE[type] : unitPrice * count;
56	    total += base + base * FIRST_INSURANCE_SURCHARGE_RATE;
57	    policyBase += base;
58	  }
59	  if (customer.yearsWithMHPCO >= 2) {
60	    total -= policyBase * 0.2;
61	  }
62	  if ((context?.previousQuoteCount ?? 0) > 0) {
63	    total -= policyBase * 0.15;
64	  }
65	  total += PROCESSING_FEE;
66	  return Math.ceil(total);
67	}
68	
69	const INSURANCE_VALUES: Record<string, number> = {
70	  sword: 1000,
71	  amulet: 600,
72	  staff: 800,
73	  potion: 400,
74	  rune: 250,
75	  moonstone: 250,
76	};
77	
78	export function claim(
79	  items: Item[],
80	  damages: Array<{ itemType: string; amount: number }>,
81	  remainingCap?: number,
82	): { payout: number; remainingCap: number } {
83	  const insuranceSum = items.reduce((sum, it) => sum + (INSURANCE_VALUES[it.type] ?? 0), 0);
84	  const cap = remainingCap ?? 2 * insuranceSum;
85	  const itemCounts: Record<string, number> = {};
86	  for (const it of items) {
87	    itemCounts[it.type] = (itemCounts[it.type] ?? 0) + 1;
88	  }
89	  const damageCounts: Record<string, number> = {};
90	  for (const d of damages) {
91	    damageCounts[d.itemType] = (damageCounts[d.itemType] ?? 0) + 1;
92	  }
93	  for (const type of Object.keys(damageCounts)) {
94	    if (damageCounts[type] > (itemCounts[type] ?? 0)) {
95	      throw new Error(`More damage entries for ${type} than insured items`);
96	    }
97	  }
98	  let total = 0;
99	  for (const damage of damages) {
100	    const item = items.find((i) => i.type === damage.itemType);
101	    const reimbursable = (item?.enchantment ?? 0) >= 8 ? damage.amount * 0.5 : damage.amount;
102	    total += Math.max(0, reimbursable - 100);
103	  }
104	  const payout = Math.min(Math.floor(total), cap);
105	  return { payout, remainingCap: cap - payout };
106	}
